import os

C = {
    "reset": "\033[0m", "bold": "\033[1m", "dim": "\033[2m",
    "cyan": "\033[96m", "green": "\033[92m", "yellow": "\033[93m",
    "red": "\033[91m", "blue": "\033[94m", "mag": "\033[95m",
    "gray": "\033[90m",
}

W = 54

def enable_ansi():
    if os.name == "nt":
        os.system("")

def box_top(title=""):
    if title:
        t = f" {title} "
        pad = W - 2 - len(t)
        left = pad // 2
        right = pad - left
        print(f"{C['cyan']}╔{'═' * left}{C['bold']}{t}{C['reset']}{C['cyan']}{'═' * right}╗{C['reset']}")
    else:
        print(f"{C['cyan']}╔{'═' * (W - 2)}╗{C['reset']}")

def box_line(text="", color=""):
    raw = strip(text)
    pad = W - 4 - len(raw)
    pad = max(pad, 0)
    print(f"{C['cyan']}║{C['reset']} {color}{text}{C['reset']}{' ' * pad} {C['cyan']}║{C['reset']}")

def box_sep():
    print(f"{C['cyan']}╟{'─' * (W - 2)}╢{C['reset']}")

def box_bottom():
    print(f"{C['cyan']}╚{'═' * (W - 2)}╝{C['reset']}")

def strip(s):
    import re
    return re.sub(r'\033\[[0-9;]*m', '', s)

def bar(ratio, width=30):
    filled = int(min(ratio, 1.0) * width)
    return "█" * filled + C['gray'] + "░" * (width - filled) + C['reset']

def calculate_bmi(weight, height):
    return weight / (height ** 2)

def get_category(bmi):
    if bmi < 18.5:
        return "Underweight", C['blue']
    elif bmi < 25:
        return "Normal weight", C['green']
    elif bmi < 30:
        return "Overweight", C['yellow']
    else:
        return "Obese", C['red']

def bmi_status(bmi, height):
    low, high = 18.5, 24.9
    if bmi < low:
        diff = low - bmi
        kg = diff * (height ** 2)
        return f"Under range by {diff:.1f} pts  (gain ~{kg:.1f} kg)", C['blue']
    elif bmi > high:
        diff = bmi - high
        kg = diff * (height ** 2)
        return f"Over range by {diff:.1f} pts  (lose ~{kg:.1f} kg)", C['yellow']
    else:
        return "Within healthy range", C['green']

def base_pack_weight(weight, days, season):
    season_factor = {"summer": 0.18, "spring": 0.22, "autumn": 0.22, "winter": 0.30}
    factor = season_factor.get(season, 0.22)
    return weight * factor + days * 1.8

def pack_advice(weight, pack):
    ratio = pack / weight * 100
    if ratio <= 10:
        return ratio, "Very light", C['green']
    elif ratio <= 20:
        return ratio, "Recommended range", C['green']
    elif ratio <= 30:
        return ratio, "Heavy but manageable", C['yellow']
    else:
        return ratio, "Too heavy - reduce load", C['red']

def water_needs(hours, temp):
    base = 0.5 * hours
    if temp >= 25:
        base *= 1.5
    elif temp >= 15:
        base *= 1.2
    return base

def calorie_needs(weight, hours, terrain):
    terrain_factor = {"flat": 4.0, "hilly": 6.0, "mountain": 8.0}
    return weight * terrain_factor.get(terrain, 6.0) * hours

def gear_checklist(days, season, terrain, temp, water):
    essentials = [
        "Backpack with rain cover",
        "Map & compass / GPS",
        "Headlamp + spare batteries",
        "First aid kit",
        "Multi-tool / knife",
        "Lighter + waterproof matches",
        f"Water bottles/bladder ({water:.1f} L/day)",
        "Water purification (filter/tablets)",
        "Sunscreen & lip balm",
        "Trekking poles",
    ]
    clothing = ["Moisture-wicking base layers", "Hiking boots + spare socks", "Rain jacket", "Hat & sunglasses"]
    if season == "winter" or temp < 5:
        clothing += ["Insulated jacket", "Thermal layers", "Gloves & beanie", "Gaiters"]
    elif temp < 15:
        clothing += ["Fleece / mid-layer", "Light gloves"]

    food = [f"Trail meals x{days}", f"Snacks/energy bars x{days * 3}", "Electrolyte mix"]

    if days > 1:
        camp = ["Tent / shelter", "Sleeping bag", "Sleeping pad", "Stove + fuel", "Cookware & utensils"]
        if season == "winter":
            camp.append("4-season rated sleeping bag")
    else:
        camp = []

    terrain_gear = []
    if terrain == "mountain":
        terrain_gear = ["Crampons / microspikes", "Helmet", "Climbing rope (if technical)"]
    elif terrain == "hilly":
        terrain_gear = ["Knee support / brace"]

    return [
        ("Essentials", essentials),
        ("Clothing", clothing),
        ("Food", food),
        ("Camp", camp),
        ("Terrain-specific", terrain_gear),
    ]

def print_checklist(sections):
    print()
    box_top("GEAR CHECKLIST")
    first = True
    for title, items in sections:
        if not items:
            continue
        if not first:
            box_sep()
        first = False
        box_line(title.upper(), C['bold'])
        for it in items:
            box_line(f"{C['green']}[ ]{C['reset']} {it}", "")
    box_bottom()
    print()

def ask(prompt):
    return input(f"{C['mag']}›{C['reset']} {prompt}{C['dim']}").strip() + C['reset']

def main():
    enable_ansi()
    print()
    box_top("HIKER BMI & TREK PLANNER")
    box_line("Plan your body and your pack", C['dim'])
    box_bottom()
    print()

    while True:
        try:
            weight = float(input(f"{C['mag']}›{C['reset']} Weight (kg): "))
            height = float(input(f"{C['mag']}›{C['reset']} Height (m):  "))
            if weight <= 0 or height <= 0:
                print(f"{C['red']}Enter positive values.{C['reset']}\n")
                continue

            bmi = calculate_bmi(weight, height)
            category, ccol = get_category(bmi)
            status, scol = bmi_status(bmi, height)
            scale = min(max((bmi - 10) / 30, 0), 1)

            print()
            box_top("RESULT")
            box_line(f"BMI        {C['bold']}{bmi:.1f}{C['reset']}", "")
            box_line(f"Category   {category}", ccol)
            box_line(f"Status     {status}", scol)
            box_line()
            box_line(bar(scale), "")
            box_line(f"{C['gray']}10{' ' * 22}25{' ' * 12}40{C['reset']}", "")
            box_bottom()
            print()

            print(f"{C['dim']}--- Trek details ---{C['reset']}")
            days = int(input(f"{C['mag']}›{C['reset']} Days:            "))
            season = input(f"{C['mag']}›{C['reset']} Season:          ").strip().lower()
            hours = float(input(f"{C['mag']}›{C['reset']} Hours/day:       "))
            temp = float(input(f"{C['mag']}›{C['reset']} Avg temp (C):    "))
            terrain = input(f"{C['mag']}›{C['reset']} Terrain:         ").strip().lower()

            pack = base_pack_weight(weight, days, season)
            ratio, note, pcol = pack_advice(weight, pack)
            water = water_needs(hours, temp)
            calories = calorie_needs(weight, hours, terrain)

            print()
            box_top("TREK PLAN")
            box_line(f"Pack weight    {C['bold']}{pack:.1f} kg{C['reset']}  ({ratio:.0f}% body wt)", "")
            box_line(f"  {note}", pcol)
            box_sep()
            box_line(f"Water / day    {water:.1f} L", C['blue'])
            box_line(f"Water total    {water * days:.1f} L", C['blue'])
            box_line(f"Calories / day {calories:.0f} kcal", C['yellow'])
            box_bottom()
            print()

            want_list = input(f"{C['mag']}›{C['reset']} Generate gear checklist? (y/n): ").strip().lower()
            if want_list == "y":
                sections = gear_checklist(days, season, terrain, temp, water)
                print_checklist(sections)

        except ValueError:
            print(f"{C['red']}Invalid input. Numbers only where required.{C['reset']}\n")
            continue

        again = input(f"{C['mag']}›{C['reset']} Plan another? (y/n): ").strip().lower()
        if again != "y":
            print(f"\n{C['green']}Happy trails!{C['reset']}\n")
            break
        print()

if __name__ == "__main__":
    main()
